const _body = $json.body || $json; if (_body._smoke_test) return [{ json: { ok: true, smoke_test: true } }];
// ---- Pillar 3: Content Extractor — Firecrawl → competitor_articles ----
// Input: { url: '...', competitor_domain: '...' }
// 1) Firecrawl scrape → markdown
// 2) Extract title, meta_description, word_count
// 3) Upsert into competitor_articles (url UNIQUE — safe to re-run)
// 4) Fire threat-assessor webhook for this article
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const url = String(b.url || '').trim();
const domain = String(b.competitor_domain || new URL(url).hostname.replace('www.', '')).trim();

if (!url.startsWith('http')) return [{ json: { ok: false, error: 'Invalid URL' } }];

// 1) Firecrawl scrape
let markdown = '';
if (ENV.FIRECRAWL_API_KEY) {
  try {
    const fcRes = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.firecrawl.dev/v1/scrape',
      headers: { Authorization: `Bearer ${ENV.FIRECRAWL_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ url, formats: ['markdown'], onlyMainContent: true }),
      json: true, timeout: 30000
    });
    markdown = fcRes.data?.markdown || '';
  } catch (e) { return [{ json: { ok: false, error: `Firecrawl failed: ${e.message.slice(0,100)}`, url } }]; }
}

if (!markdown || markdown.length < 100) return [{ json: { ok: false, error: 'No content extracted', url } }];

// 2) Extract metadata from markdown
// Title: first # heading or first non-empty line
const titleMatch = markdown.match(/^#\s+(.+)$/m) || markdown.match(/^(.{10,80})$/m);
const title = (titleMatch?.[1] || url.split('/').pop() || url).replace(/[\[\]\(\)]/g, '').slice(0, 200);

// Meta description: first substantive paragraph (under 160 chars)
const paraMatch = markdown.replace(/^#.+$/mg, '').match(/([A-Z][^\n]{30,160}[.!?])/);
const metaDescription = paraMatch?.[1]?.trim().slice(0, 160) || '';

// Word count from clean text
const wordCount = markdown.replace(/[#*`\[\]()]/g, '').split(/\s+/).filter(Boolean).length;

// 3) Upsert to Supabase
const row = {
  competitor_domain: domain,
  url,
  title,
  word_count: wordCount,
  meta_description: metaDescription,
  detected_at: new Date().toISOString()
};

if (ENV.SUPABASE_URL) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/competitor_articles?on_conflict=url`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify(row), json: false, timeout: 15000
  }).catch(() => null);
}

// 4) Fire threat-assessor for this article (async, don't block response)
this.helpers.httpRequest({
  method: 'POST',
  url: 'http://localhost:5678/webhook/competitor/assess-threat',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ url, domain, title, content_preview: markdown.slice(0, 2000) }),
  json: true, timeout: 5000
}).catch(() => null);

return [{ json: { ok: true, url, domain, title, word_count: wordCount, meta_description: metaDescription } }];
